 1→export const STAR_COLORS = ['#5f92ff', '#ff5fa2', '#5fffb0', '#ffd75f', '#b05fff', '#ff8a5f'];
 2→
 3→export const MIN_UNIVERSE_ZOOM = 0.02;
 4→export const MAX_UNIVERSE_ZOOM = 5;
 5→export const HOME_SCALE = 0.8;
 6→export const GUEST_SCALE = 0.05;
 7→
 8→export const simpleHash = (str) => {
 9→    let h = 0;
10→    for (let i = 0; i < str.length; i++) {
11→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
12→    }
13→    return Math.abs(h);
14→};
15→
16→export const userHomeCoords = (userId) => {
17→    if (!userId) return { x: 0, y: 0 };
18→    const mid = Math.floor(userId.length / 2);
19→    const xHash = simpleHash(userId.slice(0, mid));
20→    const yHash = simpleHash(userId.slice(mid));
21→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
22→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
23→    return { x, y };
24→};
25→
26→export const getStarColor = (userId) => {
27→    if (!userId) return STAR_COLORS[0];
28→    return STAR_COLORS[simpleHash(userId) % STAR_COLORS.length];
29→};
30→
31→export const getStarRadius = (likeCount) => {
32→    const likes = Math.min(likeCount || 0, 20);
33→    return 6 + likes * 0.3;
34→};
35→
36→export const extractSnippet = (post) => {
37→    if (post.post_type === 'canvas' && post.canvas_doc?.snippets) {
38→        return post.canvas_doc.snippets
39→            .map(s => s?.text || '')
40→            .filter(Boolean)
41→            .join(' ')
42→            .slice(0, 200);
43→    }
44→    if (typeof post.content === 'string') {
45→        try {
46→            const parsed = JSON.parse(post.content);
47→            const extractText = (node) => {
48→                if (!node) return '';
49→                if (typeof node.text === 'string') return node.text;
50→                if (Array.isArray(node.children)) {
51→                    return node.children.map(extractText).join('');
52→                }
53→                return '';
54→            };
55→            return extractText(parsed.root || parsed).slice(0, 200);
56→        } catch {
57→            return post.content.slice(0, 200);
58→        }
59→    }
60→    return '';
61→};
62→
63→export const hexToRgba = (hex, alpha) => {
64→    const r = parseInt(hex.slice(1, 3), 16);
65→    const g = parseInt(hex.slice(3, 5), 16);
66→    const b = parseInt(hex.slice(5, 7), 16);
67→    return `rgba(${r},${g},${b},${alpha})`;
68→};
