 21→/**
 22→ * useStarPhysics — owns the Matter.js engine for star-level physics.
 23→ *
 24→ * Stars get real velocity, collision, air friction, semantic gravity,
 25→ * constellation constraints, and interactive drag-and-throw.
 26→ */
 27→export default function useStarPhysics({
 28→    posts,
 29→    activePostIds,
 30→    galaxyPositions,
 31→    starPulls,
 32→    similarPairs,
 33→    starPullOffsets,
 34→    isGalaxySettled,
 35→    camera,
 36→    zoom,
 37→    stageSize,
 38→    isStarDragging,
 39→    enabled = true,
 40→}) {
 41→    const [starBodyPositions, setStarBodyPositions] = useState(() => new Map());
 42→
 43→    // Refs for the physics engine — not in React state
 44→    const engineRef = useRef(null);
 45→    const bodiesRef = useRef(new Map());          // postId → Matter.Body
 46→    const anchorsRef = useRef(new Map());          // postId → {x, y} anchor target
 47→    const constraintsRef = useRef(new Map());      // "postA|postB" → Matter.Constraint
 48→    const staticTimesRef = useRef(new Map());      // postId → timestamp when set to static
 49→    const rafRef = useRef(null);
 50→    const frameCountRef = useRef(0);
 51→    const lastCleanupRef = useRef(Date.now());
 52→
 53→    // Drag state
 54→    const dragBodyRef = useRef(null);
 55→    const dragConstraintRef = useRef(null);
 56→    const dragPointRef = useRef(null);             // {x,y} fixed world point
 57→
 58→    // Keep latest values in refs for the RAF loop (avoids stale closures)
 59→    const galaxyPositionsRef = useRef(galaxyPositions);
 60→    const semanticMapsRef = useRef({ starPullMap: new Map(), pairMap: new Map() });
 61→    const cameraRef = useRef(camera);
 62→    const zoomRef = useRef(zoom);
 63→    const stageSizeRef = useRef(stageSize);
 64→    const postsMapRef = useRef(new Map());
 65→
 66→    // Sync refs
 67→    galaxyPositionsRef.current = galaxyPositions;
 68→    cameraRef.current = camera;
 69→    zoomRef.current = zoom;
 70→    stageSizeRef.current = stageSize;
 71→
 72→    // Build a postId → post lookup
 73→    useEffect(() => {
 74→        const map = new Map();
 75→        if (Array.isArray(posts)) {
 76→            for (const p of posts) {
 77→                if (p?.id) map.set(p.id, p);
 78→            }
 79→        }
 80→        postsMapRef.current = map;
 81→    }, [posts]);
 82→
 83→    // Pre-process semantic data into O(1) maps
 84→    useEffect(() => {
 85→        semanticMapsRef.current = buildSemanticMaps(starPulls, similarPairs);
 86→    }, [starPulls, similarPairs]);
 87→
 88→    // ── Create engine on mount ────────────────────────────────────────
 89→    useEffect(() => {
 90→        if (!enabled) return;
 91→
 92→        engineRef.current = createStarEngine();
 93→
 94→        return () => {
 95→            if (rafRef.current) {
 96→                cancelAnimationFrame(rafRef.current);
 97→                rafRef.current = null;
 98→            }
 99→            if (engineRef.current) {
100→                World.clear(engineRef.current.world, false);
101→                Engine.clear(engineRef.current);
102→                engineRef.current = null;
103→            }
104→            bodiesRef.current.clear();
105→            anchorsRef.current.clear();
106→            constraintsRef.current.clear();
107→            staticTimesRef.current.clear();
108→        };
109→    }, [enabled]);
110→
111→    // ── Helper: compute a star's static position (same as getComputedStarPosition) ─
112→    const computeStaticPosition = useCallback((post) => {
113→        if (!post) return null;
114→        const uid = post.users?.id ?? post.user_id;
115→        const hashGal = userHomeCoords(uid);
116→        const animGal = galaxyPositionsRef.current?.get(uid);
117→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
118→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
119→        const pull = starPullOffsets?.get(post.id);
120→
121→        const baseX = post.universe_x ?? post.display_x;
122→        const baseY = post.universe_y ?? post.display_y;
123→        if (baseX == null || baseY == null) return null;
124→
125→        return {
126→            x: baseX + galDx + (pull?.dx ?? 0),
127→            y: baseY + galDy + (pull?.dy ?? 0),
128→        };
129→    }, [starPullOffsets]);
130→
131→    // ── Body lifecycle: create/activate/deactivate based on activePostIds ──
132→    useEffect(() => {
133→        if (!enabled || !engineRef.current) return;
134→        if (!(activePostIds instanceof Set) || activePostIds.size === 0) return;
135→
136→        const engine = engineRef.current;
137→        const bodies = bodiesRef.current;
138→        const anchors = anchorsRef.current;
139→        const staticTimes = staticTimesRef.current;
140→
141→        // Activate or create bodies for active posts
142→        let created = 0;
143→        for (const postId of activePostIds) {
144→            if (created >= PHYSICS_CONFIG.maxActiveBodies) break;
145→
146→            const existing = bodies.get(postId);
147→            if (existing) {
148→                // Re-awaken if it was static
149→                if (existing.isStatic) {
150→                    Body.setStatic(existing, false);
151→                    staticTimes.delete(postId);
152→                }
153→                created++;
154→                continue;
155→            }
156→
157→            // Create new body
158→            const post = postsMapRef.current.get(postId);
159→            if (!post) continue;
160→
161→            const pos = computeStaticPosition(post);
162→            if (!pos) continue;
163→
164→            const likeCount = post.like_count != null
165→                ? post.like_count
166→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
167→                    ? post.likes[0].count : 0);
168→            const radius = getStarRadius(likeCount);
169→            const mass = getStarMass(likeCount);
170→
171→            const body = createStarBody(postId, pos.x, pos.y, radius, mass);
172→            World.add(engine.world, body);
173→            bodies.set(postId, body);
174→            anchors.set(postId, { x: pos.x, y: pos.y });
175→            created++;
176→        }
177→
178→        // Deactivate bodies that left active set → make static
179→        for (const [postId, body] of bodies.entries()) {
180→            if (!activePostIds.has(postId) && !body.isStatic) {
181→                Body.setStatic(body, true);
182→                staticTimes.set(postId, Date.now());
183→            }
184→        }
185→    }, [enabled, activePostIds, computeStaticPosition]);
186→
187→    // ── Constellation constraints from similarPairs ────────────────────
188→    useEffect(() => {
189→        if (!enabled || !engineRef.current) return;
190→
191→        const engine = engineRef.current;
192→        const bodies = bodiesRef.current;
193→        const constraints = constraintsRef.current;
194→        const { pairMap } = semanticMapsRef.current;
195→
196→        // Remove old constraints
197→        for (const [key, constraint] of constraints.entries()) {
198→            World.remove(engine.world, constraint);
199→            constraints.delete(key);
200→        }
201→
202→        if (pairMap.size === 0) return;
203→
204→        // Build new constraints where both bodies are active
205→        const seen = new Set();
206→        for (const [postId, pairs] of pairMap.entries()) {
207→            const bodyA = bodies.get(postId);
208→            if (!bodyA || bodyA.isStatic) continue;
209→
210→            for (const { otherPostId, similarity } of pairs) {
211→                const pairKey = postId < otherPostId
212→                    ? `${postId}|${otherPostId}`
213→                    : `${otherPostId}|${postId}`;
214→                if (seen.has(pairKey)) continue;
215→                seen.add(pairKey);
216→
217→                const bodyB = bodies.get(otherPostId);
218→                if (!bodyB || bodyB.isStatic) continue;
219→
220→                const constraint = createConstellationConstraint(bodyA, bodyB, similarity);
221→                World.add(engine.world, constraint);
222→                constraints.set(pairKey, constraint);
223→            }
224→        }
225→    }, [enabled, similarPairs, activePostIds]);
226→
227→    // ── Update anchor targets when galaxy positions change ──────────────
228→    useEffect(() => {
229→        if (!enabled) return;
230→        const anchors = anchorsRef.current;
231→        const bodies = bodiesRef.current;
232→
233→        for (const [postId] of bodies.entries()) {
234→            const post = postsMapRef.current.get(postId);
235→            if (!post) continue;
236→            const pos = computeStaticPosition(post);
237→            if (pos) {
238→                anchors.set(postId, pos);
239→            }
240→        }
241→    }, [enabled, galaxyPositions, starPullOffsets, computeStaticPosition]);
242→
243→    // ── RAF loop: apply forces + step engine + push positions ──────────
244→    useEffect(() => {
245→        if (!enabled || !engineRef.current) return;
246→
247→        let active = true;
248→
249→        const tick = () => {
250→            if (!active || !engineRef.current) return;
251→
252→            const engine = engineRef.current;
253→            const bodies = bodiesRef.current;
254→            const anchors = anchorsRef.current;
255→            const staticTimes = staticTimesRef.current;
256→            const { starPullMap } = semanticMapsRef.current;
257→            const galPositions = galaxyPositionsRef.current;
258→
259→            // Apply forces to each awake body
260→            for (const [postId, body] of bodies.entries()) {
261→                if (body.isStatic || body.isSleeping) continue;
262→                // Skip dragged body — constraint handles it
263→                if (dragBodyRef.current === body) continue;
264→
265→                const anchor = anchors.get(postId);
266→                if (anchor) {
267→                    const anchorForce = computeAnchorForce(
268→                        body.position,
269→                        anchor,
270→                        PHYSICS_CONFIG.anchorSpringK
271→                    );
272→                    Body.applyForce(body, body.position, {
273→                        x: anchorForce.fx * body.mass,
274→                        y: anchorForce.fy * body.mass,
275→                    });
276→                }
277→
278→                if (starPullMap.size > 0 && galPositions?.size > 0) {
279→                    const pullForce = computeSemanticPullForce(
280→                        body.position,
281→                        postId,
282→                        starPullMap,
283→                        galPositions,
284→                        PHYSICS_CONFIG.semanticPullK
285→                    );
286→                    Body.applyForce(body, body.position, {
287→                        x: pullForce.fx * body.mass,
288→                        y: pullForce.fy * body.mass,
289→                    });
290→                }
291→            }
292→
293→            // Step the engine at fixed 60fps timestep
294→            Engine.update(engine, 1000 / 60);
295→
296→            frameCountRef.current++;
297→
298→            // Push positions to React every N frames
299→            if (frameCountRef.current % PHYSICS_CONFIG.renderEvery === 0) {
300→                const next = new Map();
301→                for (const [postId, body] of bodies.entries()) {
302→                    next.set(postId, { x: body.position.x, y: body.position.y });
303→                }
304→                setStarBodyPositions(next);
305→            }
306→
307→            // Periodic cleanup: remove bodies that have been static for too long
308→            const now = Date.now();
309→            if (now - lastCleanupRef.current > 10000) {
310→                lastCleanupRef.current = now;
311→                for (const [postId, timestamp] of staticTimes.entries()) {
312→                    if (now - timestamp > PHYSICS_CONFIG.staticTimeout) {
313→                        const body = bodies.get(postId);
314→                        if (body) {
315→                            World.remove(engine.world, body);
316→                            bodies.delete(postId);
317→                            anchors.delete(postId);
318→                        }
319→                        staticTimes.delete(postId);
320→                    }
321→                }
322→            }
323→
324→            rafRef.current = requestAnimationFrame(tick);
325→        };
326→
327→        rafRef.current = requestAnimationFrame(tick);
328→
329→        return () => {
330→            active = false;
331→            if (rafRef.current) {
332→                cancelAnimationFrame(rafRef.current);
333→                rafRef.current = null;
334→            }
335→        };
336→    }, [enabled]);
337→
338→    // ── Drag handlers ──────────────────────────────────────────────────
339→
340→    const handleStarPointerDown = useCallback((postId, screenX, screenY) => {
341→        if (!engineRef.current) return;
342→        const body = bodiesRef.current.get(postId);
343→        if (!body) return;
344→
345→        isStarDragging.current = true;
346→
347→        // Wake up the body if sleeping
348→        if (body.isSleeping) {
349→            Body.set(body, 'isSleeping', false);
350→        }
351→
352→        const worldPos = screenToWorld(
353→            screenX, screenY,
354→            cameraRef.current, zoomRef.current, stageSizeRef.current
355→        );
356→
357→        // Create a temporary fixed-point constraint
358→        dragPointRef.current = { x: worldPos.x, y: worldPos.y };
359→        dragBodyRef.current = body;
360→
361→        const constraint = Constraint.create({
362→            bodyA: body,
363→            pointB: dragPointRef.current,
364→            length: 0,
365→            stiffness: 0.1,
366→            damping: 0.05,
367→        });
368→
369→        World.add(engineRef.current.world, constraint);
370→        dragConstraintRef.current = constraint;
371→    }, []);
372→
373→    const handlePointerMove = useCallback((screenX, screenY) => {
374→        if (!isStarDragging.current || !dragConstraintRef.current) return;
375→
376→        const worldPos = screenToWorld(
377→            screenX, screenY,
378→            cameraRef.current, zoomRef.current, stageSizeRef.current
379→        );
380→
381→        // Update the constraint's fixed world point
382→        dragConstraintRef.current.pointB.x = worldPos.x;
383→        dragConstraintRef.current.pointB.y = worldPos.y;
384→    }, []);
385→
386→    const handlePointerUp = useCallback(() => {
387→        if (!isStarDragging.current) return;
388→
389→        if (dragConstraintRef.current && engineRef.current) {
390→            World.remove(engineRef.current.world, dragConstraintRef.current);
391→        }
392→
393→        dragConstraintRef.current = null;
394→        dragBodyRef.current = null;
395→        dragPointRef.current = null;
396→        isStarDragging.current = false;
397→    }, []);
398→
399→    return {
400→        starBodyPositions,
401→        handleStarPointerDown,
402→        handlePointerMove,
403→        handlePointerUp,
404→    };
405→}
