 1→/**
 2→ * Pure force computation functions for star-level physics.
 3→ * No React or Matter.js dependency — just math.
 4→ */
 5→
 6→/**
 7→ * Pre-processes server data into O(1) lookup Maps.
 8→ * @param {Array} starPulls - [{post_id, galaxy_user_id, similarity}, ...]
 9→ * @param {Array} similarPairs - [{post_a, post_b, similarity}, ...]
10→ * @returns {{ starPullMap: Map, pairMap: Map }}
11→ */
12→export function buildSemanticMaps(starPulls, similarPairs) {
13→    const starPullMap = new Map();
14→    if (Array.isArray(starPulls)) {
15→        for (const pull of starPulls) {
16→            if (!pull?.post_id || !pull?.galaxy_user_id) continue;
17→            let list = starPullMap.get(pull.post_id);
18→            if (!list) {
19→                list = [];
20→                starPullMap.set(pull.post_id, list);
21→            }
22→            list.push({
23→                galaxyUserId: pull.galaxy_user_id,
24→                similarity: Number(pull.similarity) || 0,
25→            });
26→        }
27→    }
28→
29→    const pairMap = new Map();
30→    if (Array.isArray(similarPairs)) {
31→        for (const pair of similarPairs) {
32→            if (!pair?.post_a || !pair?.post_b) continue;
33→            const sim = Number(pair.similarity) || 0;
34→
35→            let listA = pairMap.get(pair.post_a);
36→            if (!listA) {
37→                listA = [];
38→                pairMap.set(pair.post_a, listA);
39→            }
40→            listA.push({ otherPostId: pair.post_b, similarity: sim });
41→
42→            let listB = pairMap.get(pair.post_b);
43→            if (!listB) {
44→                listB = [];
45→                pairMap.set(pair.post_b, listB);
46→            }
47→            listB.push({ otherPostId: pair.post_a, similarity: sim });
48→        }
49→    }
50→
51→    return { starPullMap, pairMap };
52→}
53→
54→/**
55→ * Soft spring force toward an anchor (galaxy home) position.
56→ * @returns {{ fx: number, fy: number }}
57→ */
58→export function computeAnchorForce(bodyPos, anchorPos, springK) {
59→    const dx = anchorPos.x - bodyPos.x;
60→    const dy = anchorPos.y - bodyPos.y;
61→    return {
62→        fx: dx * springK,
63→        fy: dy * springK,
64→    };
65→}
66→
67→/**
68→ * Cross-galaxy attraction: pulls a star toward galaxies it has semantic affinity with.
69→ * @param {{ x: number, y: number }} bodyPos
70→ * @param {string} postId
71→ * @param {Map} starPullMap - from buildSemanticMaps
72→ * @param {Map} galaxyPositions - userId → {x,y}
73→ * @param {number} pullK
74→ * @returns {{ fx: number, fy: number }}
75→ */
76→export function computeSemanticPullForce(bodyPos, postId, starPullMap, galaxyPositions, pullK) {
77→    const pulls = starPullMap.get(postId);
78→    if (!pulls || pulls.length === 0) return { fx: 0, fy: 0 };
79→
80→    let fx = 0;
81→    let fy = 0;
82→
83→    for (const { galaxyUserId, similarity } of pulls) {
84→        const galPos = galaxyPositions.get(galaxyUserId);
85→        if (!galPos) continue;
86→
87→        const dx = galPos.x - bodyPos.x;
88→        const dy = galPos.y - bodyPos.y;
89→
90→        // Force scales with similarity
91→        fx += dx * pullK * similarity;
92→        fy += dy * pullK * similarity;
93→    }
94→
95→    return { fx, fy };
96→}
