 37→    );
 38→});
 39→
 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges,
 47→    starBodyPositions, onStarDragStart,
 48→}) => {
 49→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 50→    const galaxyUserIdMap = useMemo(() => {
 51→        const map = new Map();
 52→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 53→        return map;
 54→    }, [galaxies]);
 55→
 56→    // Galaxy spiral visuals — positioned at animated galaxy coords
 57→    const galaxyVisuals = useMemo(() =>
 58→        galaxies?.map(g => ({
 59→            x: g.x,
 60→            y: g.y,
 61→            ...generateGalaxyData(g.userId),
 62→            color: getStarColor(g.userId),
 63→        })) || []
 64→    , [galaxies]);
 65→
 66→    // ── Compute every star's render position ─────────────────────────
 67→    // Stars follow their parent galaxy's displacement from hash→animated,
 68→    // plus an optional pull offset toward similar galaxy centroids.
 69→    const computedStarPositions = useMemo(() => {
 70→        const map = new Map();
 71→        for (const post of posts) {
 72→            // Prefer physics-driven position when available
 73→            const physicsPos = starBodyPositions?.get(post.id);
 74→            if (physicsPos) {
 75→                map.set(post.id, physicsPos);
 76→                continue;
 77→            }
 78→
 79→            const uid = post.users?.id ?? post.user_id;
 80→
 81→            // Galaxy displacement: how far the galaxy moved from hash to animated
 82→            const hashGal = userHomeCoords(uid);
 83→            const animGal = galaxyPositions?.get(uid);
 84→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 85→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 86→
 87→            // Star pull offset (Gravity B)
 88→            const pull = starPullOffsets?.get(post.id);
 89→
 90→            // Base position = original hash+spiral coords
 91→            const baseX = post.universe_x ?? post.display_x;
 92→            const baseY = post.universe_y ?? post.display_y;
 93→
 94→            map.set(post.id, {
 95→                x: baseX + galDx + (pull?.dx ?? 0),
 96→                y: baseY + galDy + (pull?.dy ?? 0),
 97→            });
 98→        }
 99→        return map;
100→    }, [posts, galaxyPositions, starPullOffsets, starBodyPositions]);
101→
102→    const bridgePairs = useMemo(() => {
103→        const maxPairs = 120;
104→
105→        if (useEmbeddingBridges) {
106→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
107→                ? posts.filter((post) => activePostIds.has(post?.id))
108→                : posts;
109→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
110→        }
111→
112→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
113→
114→        return similarPairs
115→            .filter((pair) => Number(pair?.similarity) > 0.9)
116→            .filter((pair) => {
117→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
118→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
119→            })
120→            .slice(0, maxPairs);
121→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
122→
123→    return (
124→        <Layer {...layerProps}>
125→            {/* Semantic bridges between similar posts */}
126→            {bridgePairs.length > 0 && (
127→                <Shape
128→                    sceneFunc={(ctx) => {
129→                        for (const pair of bridgePairs) {
130→                            const posA = computedStarPositions.get(pair.post_a);
131→                            const posB = computedStarPositions.get(pair.post_b);
132→                            if (!posA || !posB) continue;
133→
134→                            const dx = posB.x - posA.x;
135→                            const dy = posB.y - posA.y;
136→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
137→
138→                            const mx = (posA.x + posB.x) / 2;
139→                            const my = (posA.y + posB.y) / 2;
140→                            const perpX = (-dy / dist) * dist * 0.06;
141→                            const perpY = (dx / dist) * dist * 0.06;
142→
143→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
144→                            ctx.lineWidth = 0.8;
145→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
146→                            ctx.shadowBlur = 4;
147→                            ctx.beginPath();
148→                            ctx.moveTo(posA.x, posA.y);
149→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
150→                            ctx.stroke();
151→                        }
152→                        ctx.shadowBlur = 0;
153→                    }}
154→                    perfectDrawEnabled={false}
155→                    listening={false}
156→                />
157→            )}
158→            {/* Spiral galaxy visuals + connection lines */}
159→            <Shape
160→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
161→                perfectDrawEnabled={false}
162→                listening={false}
163→            />
164→            {/* Galaxy name labels */}
165→            {galaxies?.map((g) => (
166→                <GalaxyLabel
167→                    key={g.userId}
168→                    x={g.x}
169→                    y={g.y}
170→                    name={g.name}
171→                    zoom={zoom}
172→                    onClick={() => onGalaxyClick(g)}
173→                />
174→            ))}
175→            {/* Stars */}
176→            {posts.map((post) => {
177→                const postUserId = post.users?.id ?? post.user_id;
178→                const color = getStarColor(postUserId);
179→                const likeCount = post.like_count != null
180→                    ? post.like_count
181→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
182→                const radius = getStarRadius(likeCount);
183→
184→                const pos = computedStarPositions.get(post.id);
185→                const x = pos?.x ?? post.universe_x ?? post.display_x;
186→                const y = pos?.y ?? post.universe_y ?? post.display_y;
187→
188→                return (
189→                    <StarGroup
190→                        key={post.id}
191→                        x={x}
192→                        y={y}
193→                        radius={radius}
194→                        color={color}
195→                        title={post.title}
196→                        showTitle={showTitles}
197→                        isPulsing={pulsingId === post.id}
198→                        onClick={() => onStarClick(post)}
199→                        onPointerDown={onStarDragStart ? (screenX, screenY) => onStarDragStart(post.id, screenX, screenY) : undefined}
200→                    />
201→                );
202→            })}
203→        </Layer>
204→    );
205→});
