  8→    const groupRef = useRef(null);
  9→    const tweenRef = useRef(null);
 10→
 11→    useEffect(() => {
 12→        const node = groupRef.current;
 13→        if (!node) return;
 14→
 15→        // Cleanup any running tween
 16→        if (tweenRef.current) {
 17→            tweenRef.current.destroy();
 18→            tweenRef.current = null;
 19→        }
 20→
 21→        if (isPulsing) {
 22→            // Phase 1: elastic scale up 1 → 1.8
 23→            const tweenUp = new Konva.Tween({
 24→                node,
 25→                scaleX: 1.8,
 26→                scaleY: 1.8,
 27→                duration: 0.35,
 28→                easing: Konva.Easings.ElasticEaseOut,
 29→                onFinish: () => {
 30→                    // Phase 2: ease back down 1.8 → 1
 31→                    const tweenDown = new Konva.Tween({
 32→                        node,
 33→                        scaleX: 1,
 34→                        scaleY: 1,
 35→                        duration: 0.25,
 36→                        easing: Konva.Easings.EaseOut,
 37→                    });
 38→                    tweenRef.current = tweenDown;
 39→                    tweenDown.play();
 40→                },
 41→            });
 42→            tweenRef.current = tweenUp;
 43→            tweenUp.play();
 44→        } else {
 45→            // Reset to default scale
 46→            node.scaleX(1);
 47→            node.scaleY(1);
 48→        }
 49→
 50→        return () => {
 51→            if (tweenRef.current) {
 52→                tweenRef.current.destroy();
 53→                tweenRef.current = null;
 54→            }
 55→        };
 56→    }, [isPulsing]);
