  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import {
  3→    createStarEngine,
  4→    createStarBody,
  5→    createConstellationConstraint,
  6→    getStarMass,
  7→    PHYSICS_CONFIG,
  8→    Engine,
  9→    Body,
 10→    World,
 11→    Constraint,
 12→} from '../physics/matterEngine';
 13→import {
 14→    buildSemanticMaps,
 15→    computeAnchorForce,
 16→    computeSemanticPullForce,
 17→} from '../physics/semanticForces';
 18→import { screenToWorld } from '../utils/coordConversion';
 19→import { userHomeCoords, getStarRadius } from '../utils/starUtils';
 20→
 21→/**
 22→ * useStarPhysics — owns the Matter.js engine for star-level physics.
 23→ *
 24→ * Stars get real velocity, collision, air friction, semantic gravity,
 25→ * constellation constraints, and interactive drag-and-throw.
 26→ */
 27→export default function useStarPhysics({
 28→    posts,
 29→    activePostIds,
 30→    galaxyPositions,
 31→    starPulls,
 32→    similarPairs,
 33→    starPullOffsets,
 34→    isGalaxySettled,
 35→    camera,
 36→    zoom,
 37→    stageSize,
 38→    isStarDragging,
 39→    enabled = true,
 40→}) {
 41→    const [starBodyPositions, setStarBodyPositions] = useState(() => new Map());
 42→
 43→    // Refs for the physics engine — not in React state
 44→    const engineRef = useRef(null);
 45→    const bodiesRef = useRef(new Map());          // postId → Matter.Body
 46→    const anchorsRef = useRef(new Map());          // postId → {x, y} anchor target
 47→    const constraintsRef = useRef(new Map());      // "postA|postB" → Matter.Constraint
 48→    const staticTimesRef = useRef(new Map());      // postId → timestamp when set to static
 49→    const rafRef = useRef(null);
 50→    const frameCountRef = useRef(0);
 51→    const lastCleanupRef = useRef(Date.now());
 52→
 53→    // Drag state
 54→    const dragBodyRef = useRef(null);
 55→    const dragConstraintRef = useRef(null);
 56→    const dragPointRef = useRef(null);             // {x,y} fixed world point
 57→
 58→    // Keep latest values in refs for the RAF loop (avoids stale closures)
 59→    const galaxyPositionsRef = useRef(galaxyPositions);
 60→    const semanticMapsRef = useRef({ starPullMap: new Map(), pairMap: new Map() });
 61→    const cameraRef = useRef(camera);
 62→    const zoomRef = useRef(zoom);
 63→    const stageSizeRef = useRef(stageSize);
 64→    const postsMapRef = useRef(new Map());
 65→
 66→    // Sync refs
 67→    galaxyPositionsRef.current = galaxyPositions;
 68→    cameraRef.current = camera;
 69→    zoomRef.current = zoom;
 70→    stageSizeRef.current = stageSize;
 71→
 72→    // Build a postId → post lookup
 73→    useEffect(() => {
 74→        const map = new Map();
 75→        if (Array.isArray(posts)) {
 76→            for (const p of posts) {
 77→                if (p?.id) map.set(p.id, p);
 78→            }
 79→        }
 80→        postsMapRef.current = map;
 81→    }, [posts]);
 82→
 83→    // Pre-process semantic data into O(1) maps
 84→    useEffect(() => {
 85→        semanticMapsRef.current = buildSemanticMaps(starPulls, similarPairs);
 86→    }, [starPulls, similarPairs]);
 87→
 88→    // ── Create engine on mount ────────────────────────────────────────
 89→    useEffect(() => {
 90→        if (!enabled) return;
 91→
 92→        engineRef.current = createStarEngine();
 93→
 94→        return () => {
 95→            if (rafRef.current) {
 96→                cancelAnimationFrame(rafRef.current);
 97→                rafRef.current = null;
 98→            }
 99→            if (engineRef.current) {
100→                World.clear(engineRef.current.world, false);
101→                Engine.clear(engineRef.current);
102→                engineRef.current = null;
103→            }
104→            bodiesRef.current.clear();
105→            anchorsRef.current.clear();
106→            constraintsRef.current.clear();
107→            staticTimesRef.current.clear();
108→        };
109→    }, [enabled]);
110→
111→    // ── Helper: compute a star's static position (same as getComputedStarPosition) ─
112→    const computeStaticPosition = useCallback((post) => {
113→        if (!post) return null;
114→        const uid = post.users?.id ?? post.user_id;
115→        const hashGal = userHomeCoords(uid);
116→        const animGal = galaxyPositionsRef.current?.get(uid);
117→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
118→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
119→        const pull = starPullOffsets?.get(post.id);
120→
121→        const baseX = post.universe_x ?? post.display_x;
122→        const baseY = post.universe_y ?? post.display_y;
123→        if (baseX == null || baseY == null) return null;
124→
125→        return {
126→            x: baseX + galDx + (pull?.dx ?? 0),
127→            y: baseY + galDy + (pull?.dy ?? 0),
128→        };
129→    }, [starPullOffsets]);
130→
131→    // ── Body lifecycle: create/activate/deactivate based on activePostIds ──
132→    useEffect(() => {
133→        if (!enabled || !engineRef.current) return;
134→        if (!(activePostIds instanceof Set) || activePostIds.size === 0) return;
135→
136→        const engine = engineRef.current;
137→        const bodies = bodiesRef.current;
138→        const anchors = anchorsRef.current;
139→        const staticTimes = staticTimesRef.current;
140→
141→        // Activate or create bodies for active posts
142→        let created = 0;
143→        for (const postId of activePostIds) {
144→            if (created >= PHYSICS_CONFIG.maxActiveBodies) break;
145→
146→            const existing = bodies.get(postId);
147→            if (existing) {
148→                // Re-awaken if it was static
149→                if (existing.isStatic) {
150→                    Body.setStatic(existing, false);
151→                    staticTimes.delete(postId);
152→                }
153→                created++;
154→                continue;
155→            }
156→
157→            // Create new body
158→            const post = postsMapRef.current.get(postId);
159→            if (!post) continue;
160→
